     1→/* -*- Mode: C; tab-width: 4; c-basic-offset: 4; indent-tabs-mode: nil -*- */
     2→// Functions related to the configuration management threads and VM
     3→// TODO (v2): move worker thread related code back out of here.
     4→
     5→#include "proxy.h"
     6→#include "vendor/routelib/routelib.h"
     7→
     8→// not using queue.h becuase those require specific storage for HEAD.
     9→// it's not possible to have the HEAD simply be in the proxy context because
    10→// it would need to know the offset into this private structure.
    11→// This might be doable but the problem is too trivial to spend time on it.
    12→#define MCP_LUAFILE_SIZE 16384
    13→struct _mcp_luafile {
    14→    size_t size;
    15→    size_t used;
    16→    bool loaded; // flip this to false before each load use
    17→    char *buf;
    18→    char *fname; // filename to load
    19→    struct _mcp_luafile *next;
    20→};
    21→
    22→static int _dump_helper(lua_State *L, const void *p, size_t sz, void *ud) {
    23→    (void)L;
    24→    struct _mcp_luafile *db = ud;
    25→    if (db->used + sz > db->size) {
    26→        // increase by blocks instead of doubling to avoid memory waste
    27→        db->size += MCP_LUAFILE_SIZE;
    28→        char *nb = realloc(db->buf, db->size);
    29→        if (nb == NULL) {
    30→            return -1;
    31→        }
    32→        db->buf = nb;
    33→    }
    34→    memcpy(db->buf + db->used, (const char *)p, sz);
    35→    db->used += sz;
    36→    return 0;
    37→}
    38→
    39→static const char * _load_helper(lua_State *L, void *data, size_t *size) {
    40→    (void)L;
    41→    struct _mcp_luafile *db = data;
    42→    if (db->loaded) {
    43→        *size = 0;
    44→        return NULL;
    45→    }
    46→    *size = db->used;
    47→    db->loaded = true;
    48→    return db->buf;
    49→}
