    51→void proxy_start_reload(void *arg) {
    52→    proxy_ctx_t *ctx = arg;
    53→    if (pthread_mutex_trylock(&ctx->config_lock) == 0) {
    54→        ctx->loading = true;
    55→        pthread_cond_signal(&ctx->config_cond);
    56→        pthread_mutex_unlock(&ctx->config_lock);
    57→    }
    58→}
