    60→int proxy_first_confload(void *arg) {
    61→    proxy_ctx_t *ctx = arg;
    62→    pthread_mutex_lock(&ctx->config_lock);
    63→    ctx->loading = true;
    64→    pthread_cond_signal(&ctx->config_cond);
    65→    pthread_mutex_unlock(&ctx->config_lock);
    66→
    67→    while (1) {
    68→        bool stop = false;
    69→        pthread_mutex_lock(&ctx->config_lock);
    70→        if (!ctx->loading) {
    71→            stop = true;
    72→        }
    73→        pthread_mutex_unlock(&ctx->config_lock);
    74→        if (stop)
    75→            break;
    76→    }
    77→    int fails = 0;
    78→    STAT_L(ctx);
    79→    fails = ctx->global_stats.config_reload_fails;
    80→    STAT_UL(ctx);
    81→    if (fails) {
    82→        return -1;
    83→    }
    84→
    85→    return 0;
    86→}
