    88→// Manages a queue of inbound objects destined to be deallocated.
    89→static void *_proxy_manager_thread(void *arg) {
    90→    proxy_ctx_t *ctx = arg;
    91→    globalobj_head_t head;
    92→
    93→    pthread_mutex_lock(&ctx->manager_lock);
    94→    while (1) {
    95→        STAILQ_INIT(&head);
    96→        while (STAILQ_EMPTY(&ctx->manager_head)) {
    97→            pthread_cond_wait(&ctx->manager_cond, &ctx->manager_lock);
    98→        }
    99→
   100→        // pull dealloc queue into local queue.
   101→        STAILQ_CONCAT(&head, &ctx->manager_head);
   102→        pthread_mutex_unlock(&ctx->manager_lock);
   103→
   104→        // Config lock is required for using config VM.
   105→        pthread_mutex_lock(&ctx->config_lock);
   106→        lua_State *L = ctx->proxy_state;
   107→        struct mcp_globalobj_s *g;
   108→        STAILQ_FOREACH(g, &head, next) {
   109→            // we let the object _gc() handle backend/etc references
   110→            pthread_mutex_lock(&g->lock);
   111→            assert(g->self_ref != -1);
   112→            // See comment on mcp_gobj_ref()
   113→            if (g->self_ref < -1) {
   114→                g->refcount--;
   115→                g->self_ref = -g->self_ref;
   116→            }
   117→            assert(g->self_ref > 0 || g->refcount == 0);
   118→            if (g->refcount == 0) {
   119→                luaL_unref(L, LUA_REGISTRYINDEX, g->self_ref);
   120→                g->self_ref = -1;
   121→            }
   122→            pthread_mutex_unlock(&g->lock);
   123→        }
   124→        // force lua garbage collection so any resources close out quickly.
   125→        lua_gc(L, LUA_GCCOLLECT);
   126→        // twice because objects with garbage collector handlers are only
   127→        // marked on the first collection cycle.
   128→        lua_gc(L, LUA_GCCOLLECT);
   129→        // must hold this lock while interacting with the config VM.
   130→        pthread_mutex_unlock(&ctx->config_lock);
   131→
   132→        // done.
   133→        pthread_mutex_lock(&ctx->manager_lock);
   134→    }
   135→
   136→    return NULL;
   137→}
