   139→// TODO: only run routine if something changed.
   140→// This compacts all of the names for proxy user stats into a linear buffer,
   141→// which can save considerable CPU when emitting a large number of stats. It
   142→// also saves some total memory by having one linear buffer instead of many
   143→// potentially small aligned allocations.
   144→static void proxy_config_stats_prep(proxy_ctx_t *ctx) {
   145→    char *oldnamebuf = ctx->user_stats_namebuf;
   146→    struct proxy_user_stats_entry *entries = ctx->user_stats;
   147→    size_t namelen = 0;
   148→
   149→    STAT_L(ctx);
   150→    // find size of new compact name buffer
   151→    for (int x = 0; x < ctx->user_stats_num; x++) {
   152→        if (entries[x].name) {
   153→            namelen += strlen(entries[x].name) + 1; // null byte
   154→        } else if (entries[x].cname) {
   155→            char *name = oldnamebuf + entries[x].cname;
   156→            namelen += strlen(name) + 1;
   157→        }
   158→    }
   159→    // start one byte into the cname buffer so we can do faster checks on if a
   160→    // name exists or not. so extend the buffer by one byte.
   161→    namelen++;
   162→
   163→    char *namebuf = calloc(1, namelen);
   164→    // copy names into the compact buffer
   165→    char *p = namebuf + 1;
   166→    for (int x = 0; x < ctx->user_stats_num; x++) {
   167→        struct proxy_user_stats_entry *e = &entries[x];
   168→        char *newname = NULL;
   169→        if (e->name) {
   170→            // skip blank names.
   171→            if (e->name[0]) {
   172→                newname = e->name;
   173→            }
   174→        } else if (e->cname) {
   175→            // else re-copy from old buffer
   176→            newname = oldnamebuf + e->cname;
   177→        }
   178→
   179→        if (newname) {
   180→            // set the buffer offset for this name
   181→            e->cname = p - namebuf;
   182→            // copy in the name
   183→            size_t nlen = strlen(newname);
   184→            memcpy(p, newname, nlen);
   185→            p += nlen;
   186→            *p = '\0'; // add null byte
   187→            p++;
   188→        } else {
   189→            // name is blank or doesn't exist, ensure we skip it.
   190→            e->cname = 0;
   191→        }
   192→
   193→        if (e->name) {
   194→            // now get rid of the name buffer.
   195→            free(e->name);
   196→            e->name = NULL;
   197→        }
   198→    }
   199→
   200→    ctx->user_stats_namebuf = namebuf;
   201→    if (oldnamebuf) {
   202→        free(oldnamebuf);
   203→    }
   204→    STAT_UL(ctx);
   205→}
