   207→static void proxy_config_reload(proxy_ctx_t *ctx) {
   208→    LOGGER_LOG(NULL, LOG_PROXYEVENTS, LOGGER_PROXY_CONFIG, NULL, "start");
   209→    STAT_INCR(ctx, config_reloads, 1);
   210→    // gen. used for tracking object lifecycles over time.
   211→    // ie: ensuring old things are unloaded.
   212→    ctx->config_generation++;
   213→    lua_State *L = ctx->proxy_state;
   214→    lua_settop(L, 0); // clear off any crud that could have been left on the stack.
   215→
   216→    // The main stages of config reload are:
   217→    // - load and execute the config file
   218→    // - run mcp_config_pools()
   219→    // - for each worker:
   220→    //   - copy and execute new lua code
   221→    //   - copy selector table
   222→    //   - run mcp_config_routes()
   223→
   224→    if (proxy_load_config(ctx) != 0) {
   225→        // Failed to load. log and wait for a retry.
   226→        STAT_INCR(ctx, config_reload_fails, 1);
   227→        LOGGER_LOG(NULL, LOG_PROXYEVENTS, LOGGER_PROXY_CONFIG, NULL, "failed");
   228→        return;
   229→    }
   230→
   231→    proxy_config_stats_prep(ctx);
   232→
   233→    // TODO (v2): create a temporary VM to test-load the worker code into.
   234→    // failing to load partway through the worker VM reloads can be
   235→    // critically bad if we're not careful about references.
   236→    // IE: the config VM _must_ hold references to selectors and backends
   237→    // as long as they exist in any worker for any reason.
   238→
   239→    for (int x = 0; x < settings.num_threads; x++) {
   240→        LIBEVENT_THREAD *thr = get_worker_thread(x);
   241→
   242→        pthread_mutex_lock(&ctx->worker_lock);
   243→        ctx->worker_done = false;
   244→        ctx->worker_failed = false;
   245→        proxy_reload_notify(thr);
   246→        while (!ctx->worker_done) {
   247→            // in case of spurious wakeup.
   248→            pthread_cond_wait(&ctx->worker_cond, &ctx->worker_lock);
   249→        }
   250→        pthread_mutex_unlock(&ctx->worker_lock);
   251→
   252→        // Code load bailed.
   253→        if (ctx->worker_failed) {
   254→            STAT_INCR(ctx, config_reload_fails, 1);
   255→            LOGGER_LOG(NULL, LOG_PROXYEVENTS, LOGGER_PROXY_CONFIG, NULL, "failed");
   256→            return;
   257→        }
   258→    }
   259→
   260→    // Need to clear the reset flag for the stats system after pushing the new
   261→    // config to each worker.
   262→    STAT_L(ctx);
   263→    for (int x = 0; x < ctx->user_stats_num; x++) {
   264→        ctx->user_stats[x].reset = false;
   265→    }
   266→    STAT_UL(ctx);
   267→
   268→    lua_pop(ctx->proxy_state, 1); // drop config_pools return value
   269→    LOGGER_LOG(NULL, LOG_PROXYEVENTS, LOGGER_PROXY_CONFIG, NULL, "done");
   270→}
