   272→// Very basic scheduler. Unsorted because we don't expect a huge list of
   273→// functions to run.
   274→static void proxy_run_crons(proxy_ctx_t *ctx) {
   275→    lua_State *L = ctx->proxy_state;
   276→    assert(lua_gettop(L) == 0);
   277→    assert(ctx->cron_ref);
   278→    struct timespec now;
   279→
   280→    // Fetch the cron table. Created on startup so must exist.
   281→    lua_rawgeti(L, LUA_REGISTRYINDEX, ctx->cron_ref);
   282→
   283→    clock_gettime(CLOCK_REALTIME, &now);
   284→    if (ctx->cron_next <= now.tv_sec) {
   285→        ctx->cron_next = INT_MAX;
   286→    } else {
   287→        // no crons ready.
   288→        return;
   289→    }
   290→
   291→    // Loop the cron entries.
   292→    lua_pushnil(L);
   293→    while (lua_next(L, 1) != 0) {
   294→        const char *key = lua_tostring(L, -2);
   295→        mcp_cron_t *ce = lua_touserdata(L, -1);
   296→        int idx = lua_absindex(L, -1);
   297→
   298→        // check generation.
   299→        if (ctx->config_generation != ce->gen) {
   300→            // remove entry.
   301→            lua_pushnil(L);
   302→            lua_setfield(L, 1, key);
   303→        } else if (ce->next <= now.tv_sec) {
   304→            // grab func and execute it
   305→            lua_getiuservalue(L, idx, 1);
   306→            // no arguments or return values
   307→            int res = lua_pcall(L, 0, 0, 0);
   308→            STAT_INCR(ctx, config_cron_runs, 1);
   309→            if (res != LUA_OK) {
   310→                LOGGER_LOG(NULL, LOG_PROXYEVENTS, LOGGER_PROXY_ERROR, NULL, lua_tostring(L, -1));
   311→                STAT_INCR(ctx, config_cron_fails, 1);
   312→                lua_pop(L, 1); // drop error.
   313→            }
   314→
   315→            if (ce->repeat) {
   316→                ce->next = now.tv_sec + ce->every;
   317→                // if rescheduled, check next against ctx. update if sooner
   318→                if (ctx->cron_next > ce->next) {
   319→                    ctx->cron_next = ce->next;
   320→                }
   321→            } else {
   322→                // non-repeating cron. delete entry.
   323→                lua_pushnil(L);
   324→                lua_setfield(L, 1, key);
   325→            }
   326→        } else {
   327→            // not scheduled to run now, but check if we're next.
   328→            if (ctx->cron_next > ce->next) {
   329→                ctx->cron_next = ce->next;
   330→            }
   331→        }
   332→
   333→        lua_pop(L, 1); // drop value so we can loop.
   334→    }
   335→
   336→    lua_pop(L, 1); // drop cron table.
   337→}
