   339→// Thread handling the configuration reload sequence.
   340→// TODO (v2): get a logger instance.
   341→// TODO (v2): making this "safer" will require a few phases of work.
   342→// 1) JFDI
   343→// 2) "test VM" -> from config thread, test the worker reload portion.
   344→// 3) "unit testing" -> from same temporary worker VM, execute set of
   345→// integration tests that must pass.
   346→// 4) run update on each worker, collecting new mcp.attach() hooks.
   347→//    Once every worker has successfully executed and set new hooks, roll
   348→//    through a _second_ time to actually swap the hook structures and unref
   349→//    the old structures where marked dirty.
   350→static void *_proxy_config_thread(void *arg) {
   351→    proxy_ctx_t *ctx = arg;
   352→    struct timespec wait = {0};
   353→
   354→    logger_create();
   355→    pthread_mutex_lock(&ctx->config_lock);
   356→    pthread_cond_signal(&ctx->config_cond);
   357→    while (1) {
   358→        ctx->loading = false;
   359→
   360→        // cron only thinks in whole seconds.
   361→        wait.tv_sec = ctx->cron_next;
   362→        pthread_cond_timedwait(&ctx->config_cond, &ctx->config_lock, &wait);
   363→
   364→        proxy_run_crons(ctx);
   365→
   366→        if (ctx->loading) {
   367→            proxy_config_reload(ctx);
   368→        }
   369→    }
   370→
   371→    return NULL;
   372→}
   373→
   374→int _start_proxy_config_threads(proxy_ctx_t *ctx) {
   375→    int ret;
   376→
   377→    pthread_mutex_lock(&ctx->config_lock);
   378→    if ((ret = pthread_create(&ctx->config_tid, NULL,
   379→                    _proxy_config_thread, ctx)) != 0) {
   380→        fprintf(stderr, "Failed to start proxy configuration thread: %s\n",
   381→                strerror(ret));
   382→        pthread_mutex_unlock(&ctx->config_lock);
   383→        return -1;
   384→    }
   385→    thread_setname(ctx->config_tid, "mc-prx-config");
   386→    // Avoid returning until the config thread has actually started.
   387→    pthread_cond_wait(&ctx->config_cond, &ctx->config_lock);
   388→    pthread_mutex_unlock(&ctx->config_lock);
   389→
   390→    pthread_mutex_lock(&ctx->manager_lock);
   391→    if ((ret = pthread_create(&ctx->manager_tid, NULL,
   392→                    _proxy_manager_thread, ctx)) != 0) {
   393→        fprintf(stderr, "Failed to start proxy manager thread: %s\n",
   394→                strerror(ret));
   395→        pthread_mutex_unlock(&ctx->manager_lock);
   396→        return -1;
   397→    }
   398→    thread_setname(ctx->manager_tid, "mc-prx-manager");
   399→    pthread_mutex_unlock(&ctx->manager_lock);
   400→
   401→    return 0;
   402→}
