   404→// this splits a list of lua startfiles into independent data chunk buffers
   405→// we call this once the first time we start so we can use mallocs without
   406→// having to armor against runtime malloc failures... as much.
   407→static int proxy_init_startfiles(proxy_ctx_t *ctx, const char *files) {
   408→    char *flist = strdup(settings.proxy_startfile);
   409→    if (flist == NULL) {
   410→        fprintf(stderr, "ERROR: failed to allocate memory for parsing proxy_startfile\n");
   411→        return -1;
   412→    }
   413→
   414→    char *b;
   415→    for (const char *p = strtok_r(flist, ":", &b);
   416→            p != NULL;
   417→            p = strtok_r(NULL, ":", &b)) {
   418→        struct _mcp_luafile *db = calloc(sizeof(struct _mcp_luafile), 1);
   419→        if (db == NULL) {
   420→            fprintf(stderr, "ERROR: failed to allocate memory for parsing proxy_startfile\n");
   421→            return -1;
   422→        }
   423→        db->size = MCP_LUAFILE_SIZE;
   424→        db->buf = calloc(db->size, 1);
   425→        db->fname = strdup(p);
   426→        if (db->buf == NULL || db->fname == NULL) {
   427→            fprintf(stderr, "ERROR: failed to allocate memory while parsing proxy_startfile\n");
   428→            return -1;
   429→        }
   430→
   431→        // put new file at tail
   432→        if (ctx->proxy_code == NULL) {
   433→            ctx->proxy_code = db;
   434→        } else {
   435→            struct _mcp_luafile *list = ctx->proxy_code;
   436→            while (list->next) {
   437→                list = list->next;
   438→            }
   439→            assert(list->next == NULL);
   440→            list->next = db;
   441→        }
   442→    }
   443→
   444→    free(flist);
   445→    return 0;
   446→}
   447→
   448→static int proxy_load_files(proxy_ctx_t *ctx) {
   449→    lua_State *L = ctx->proxy_state;
   450→    struct _mcp_luafile *db = ctx->proxy_code;
   451→    assert(db);
   452→
   453→    while (db) {
   454→        int res;
   455→        // clear the buffer for reuse.
   456→        memset(db->buf, 0, db->size);
   457→        db->used = 0;
   458→
   459→        if (strcmp(db->fname, "routelib") == 0) {
   460→            res = luaL_loadbuffer(L, routelib_lua, routelib_lua_len, "routelib");
   461→        } else {
   462→            res = luaL_loadfile(L, db->fname);
   463→        }
   464→        if (res != LUA_OK) {
   465→            fprintf(stderr, "ERROR: Failed to load proxy_startfile: %s\n", lua_tostring(L, -1));
   466→            return -1;
   467→        }
   468→        // LUA_OK, LUA_ERRSYNTAX, LUA_ERRMEM, LUA_ERRFILE
   469→
   470→        // Now we need to dump the compiled code into bytecode.
   471→        // This will then get loaded into worker threads.
   472→        lua_dump(L, _dump_helper, db, 0);
   473→        // 0 means no error.
   474→
   475→        // now we complete the data load by calling the function.
   476→        res = lua_pcall(L, 0, LUA_MULTRET, 0);
   477→        if (res != LUA_OK) {
   478→            fprintf(stderr, "ERROR: Failed to load data into lua config state: %s\n", lua_tostring(L, -1));
   479→            exit(EXIT_FAILURE);
   480→        }
   481→
   482→        db = db->next;
   483→    }
   484→
   485→    return 0;
   486→}
   487→
   488→int proxy_load_config(void *arg) {
   489→    proxy_ctx_t *ctx = arg;
   490→    lua_State *L = ctx->proxy_state;
   491→    int res = 0;
   492→
   493→    if (ctx->proxy_code == NULL) {
   494→        res = proxy_init_startfiles(ctx, settings.proxy_startfile);
   495→        if (res != 0) {
   496→            return res;
   497→        }
   498→    }
   499→
   500→    // load each of the data files in order.
   501→    res = proxy_load_files(ctx);
   502→
   503→    // call the mcp_config_pools function to get the central backends.
   504→    lua_getglobal(L, "mcp_config_pools");
   505→
   506→    if (lua_isnil(L, -1)) {
   507→        fprintf(stderr, "ERROR: Configuration file missing 'mcp_config_pools' function\n");
   508→        exit(EXIT_FAILURE);
   509→    }
   510→    lua_pushnil(L); // no "old" config yet.
   511→    if (lua_pcall(L, 1, 1, 0) != LUA_OK) {
   512→        fprintf(stderr, "ERROR: Failed to execute mcp_config_pools: %s\n", lua_tostring(L, -1));
   513→        exit(EXIT_FAILURE);
   514→    }
   515→
   516→    // result is our main config.
   517→    return 0;
   518→}
