   520→static int _copy_pool(lua_State *from, lua_State *to, LIBEVENT_THREAD *thr) {
   521→    // from, -3 should have the userdata.
   522→    mcp_pool_t *p = luaL_checkudata(from, -3, "mcp.pool");
   523→    size_t size = sizeof(mcp_pool_proxy_t);
   524→    mcp_pool_proxy_t *pp = lua_newuserdatauv(to, size, 0);
   525→    luaL_setmetatable(to, "mcp.pool_proxy");
   526→
   527→    pp->main = p;
   528→    if (p->use_iothread) {
   529→        pp->pool = p->pool;
   530→    } else {
   531→        // allow 0 indexing for backends when unique to each worker thread
   532→        pp->pool = &p->pool[thr->thread_baseid * p->pool_size];
   533→    }
   534→    lua_pushvalue(from, -3); // dupe pool for referencing
   535→    mcp_gobj_ref(from, &p->g); // pops obj copy
   536→    return 0;
   537→}
   538→
   539→static void _copy_config_table(lua_State *from, lua_State *to, LIBEVENT_THREAD *thr);
   540→// (from, -1) is the source value
   541→// should end with (to, -1) being the new value.
   542→static void _copy_config_table(lua_State *from, lua_State *to, LIBEVENT_THREAD *thr) {
   543→    int type = lua_type(from, -1);
   544→    bool found = false;
   545→    luaL_checkstack(from, 4, "configuration error: table recursion too deep");
   546→    luaL_checkstack(to, 4, "configuration error: table recursion too deep");
   547→    switch (type) {
   548→        case LUA_TNIL:
   549→            lua_pushnil(to);
   550→            break;
   551→        case LUA_TUSERDATA:
   552→            // see dump_stack() - check if it's something we handle.
   553→            if (lua_getmetatable(from, -1) != 0) {
   554→                lua_pushstring(from, "__name");
   555→                if (lua_rawget(from, -2) != LUA_TNIL) {
   556→                    const char *name = lua_tostring(from, -1);
   557→                    if (strcmp(name, "mcp.pool") == 0) {
   558→                        _copy_pool(from, to, thr);
   559→                        found = true;
   560→                    } else if (strcmp(name, "mcp.ratelim_global_tbf") == 0) {
   561→                        mcp_ratelim_proxy_tbf(from, to);
   562→                        found = true;
   563→                    }
   564→                }
   565→                lua_pop(from, 2);
   566→            }
   567→            if (!found) {
   568→                proxy_lua_error(from, "unhandled userdata type in configuration table\n");
   569→            }
   570→            break;
   571→        case LUA_TNUMBER:
   572→            if (lua_isinteger(from, -1)) {
   573→                lua_pushinteger(to, lua_tointeger(from, -1));
   574→            } else {
   575→                lua_pushnumber(to, lua_tonumber(from, -1));
   576→            }
   577→            break;
   578→        case LUA_TSTRING:
   579→            lua_pushlstring(to, lua_tostring(from, -1), lua_rawlen(from, -1));
   580→            break;
   581→        case LUA_TBOOLEAN:
   582→            lua_pushboolean(to, lua_toboolean(from, -1));
   583→            break;
   584→        case LUA_TTABLE:
   585→            // TODO (v2): copy the metatable first?
   586→            // TODO (v2): size narr/nrec from old table and use createtable to
   587→            // pre-allocate.
   588→            lua_newtable(to); // throw new table on worker
   589→            int t = lua_absindex(from, -1); // static index of table to copy.
   590→            int nt = lua_absindex(to, -1); // static index of new table.
   591→            lua_pushnil(from); // start iterator for main
   592→            while (lua_next(from, t) != 0) {
   593→                // (key, -2), (val, -1)
   594→                int keytype = lua_type(from, -2);
   595→                // to intentionally limit complexity and allow for future
   596→                // optimizations we restrict what types may be used as keys
   597→                // for sub-tables.
   598→                switch (keytype) {
   599→                    case LUA_TSTRING:
   600→                        // to[l]string converts the actual key in the table
   601→                        // into a string, so we must not do that unless it
   602→                        // already is one.
   603→                        lua_pushlstring(to, lua_tostring(from, -2), lua_rawlen(from, -2));
   604→                        break;
   605→                    case LUA_TNUMBER:
   606→                        if (lua_isinteger(from, -2)) {
   607→                            lua_pushinteger(to, lua_tointeger(from, -2));
   608→                        } else {
   609→                            lua_pushnumber(to, lua_tonumber(from, -2));
   610→                        }
   611→                        break;
   612→                    default:
   613→                        proxy_lua_error(from, "configuration table keys must be strings or numbers");
   614→                }
   615→                // lua_settable(to, n) - n being the table
   616→                // takes -2 key -1 value, pops both.
   617→                // use lua_absindex(L, -1) and so to convert easier?
   618→                _copy_config_table(from, to, thr); // push next value.
   619→                lua_settable(to, nt);
   620→                lua_pop(from, 1); // drop value, keep key.
   621→            }
   622→            // top of from is now the original table.
   623→            // top of to should be the new table.
   624→            break;
   625→        default:
   626→            proxy_lua_error(from, "unhandled data type in configuration table\n");
   627→    }
   628→}
   629→
   630→// Run from proxy worker to coordinate code reload.
   631→// config_lock must be held first.
   632→void proxy_worker_reload(void *arg, LIBEVENT_THREAD *thr) {
   633→    proxy_ctx_t *ctx = arg;
   634→    pthread_mutex_lock(&ctx->worker_lock);
   635→    if (proxy_thread_loadconf(ctx, thr) != 0) {
   636→        ctx->worker_failed = true;
   637→    }
   638→    ctx->worker_done = true;
   639→    pthread_cond_signal(&ctx->worker_cond);
   640→    pthread_mutex_unlock(&ctx->worker_lock);
   641→}
   642→
   643→// FIXME (v2): need to test how to recover from an actual error here. error message
   644→// needs to go somewhere useful, counters added, etc.
   645→int proxy_thread_loadconf(proxy_ctx_t *ctx, LIBEVENT_THREAD *thr) {
   646→    lua_State *L = thr->L;
   647→    // load the precompiled config functions.
   648→
   649→    struct _mcp_luafile *db = ctx->proxy_code;
   650→    while (db) {
   651→        db->loaded = false;
   652→        int res = lua_load(L, _load_helper, db, "config", NULL);
   653→        if (res != LUA_OK) {
   654→            fprintf(stderr, "Failed to load data into worker thread: %s\n", lua_tostring(L, -1));
   655→            return -1;
   656→        }
   657→
   658→        res = lua_pcall(L, 0, LUA_MULTRET, 0);
   659→        if (res != LUA_OK) {
   660→            // FIXME (v2): don't exit here!
   661→            fprintf(stderr, "Failed to load data into worker thread: %s\n", lua_tostring(L, -1));
   662→            return -1;
   663→        }
   664→
   665→        db = db->next;
   666→    }
   667→
   668→    lua_getglobal(L, "mcp_config_routes");
   669→    // create deepcopy of argument to pass into mcp_config_routes.
   670→    // FIXME (v2): to avoid lua SIGABRT'ing on errors we need to protect the call
   671→    // normal pattern:
   672→    // lua_pushcfunction(L, &_copy_config_table);
   673→    // lua_pushlightuserdata(L, &L2);
   674→    // res = la_pcall(L, etc);
   675→    // ... but since this is cross-VM we could get errors from not the
   676→    // protected VM, breaking setjmp/etc.
   677→    // for this part of the code we should override lua_atpanic(),
   678→    // allowing us to specifically recover and bail.
   679→    // However, again, this will require the next version of the config reload
   680→    // code since we are re-using the VM's and a panic can leave us in a
   681→    // broken state.
   682→    // If the setjump/longjump combos are compatible a pcall for from and
   683→    // atpanic for to might work best, since the config VM is/should be long
   684→    // running and worker VM's should be rotated.
   685→    _copy_config_table(ctx->proxy_state, L, thr);
   686→
   687→    // copied value is in front of route function, now call it.
   688→    if (lua_pcall(L, 1, 0, 0) != LUA_OK) {
   689→        fprintf(stderr, "Failed to execute mcp_config_routes: %s\n", lua_tostring(L, -1));
   690→        return -1;
   691→    }
   692→
   693→    // update user stats
   694→    STAT_L(ctx);
   695→    struct proxy_user_stats_entry *us = ctx->user_stats;
   696→    int stats_num = ctx->user_stats_num;
   697→    struct proxy_user_stats *tus = NULL;
   698→    if (stats_num != 0) {
   699→        pthread_mutex_lock(&thr->stats.mutex);
   700→        if (thr->proxy_user_stats == NULL) {
   701→            tus = calloc(1, sizeof(struct proxy_user_stats));
   702→            thr->proxy_user_stats = tus;
   703→        } else {
   704→            tus = thr->proxy_user_stats;
   705→        }
   706→
   707→        // originally this was a realloc routine but it felt fragile.
   708→        // that might still be a better idea; still need to zero out the end.
   709→        uint64_t *counters = calloc(stats_num, sizeof(uint64_t));
   710→
   711→        // note that num_stats can _only_ grow in size.
   712→        if (tus->counters) {
   713→            // pull in old counters, if the names didn't change.
   714→            for (int x = 0; x < tus->num_stats; x++) {
   715→                if (us[x].reset) {
   716→                    counters[x] = 0;
   717→                } else {
   718→                    counters[x] = tus->counters[x];
   719→                }
   720→            }
   721→            assert(tus->num_stats <= stats_num);
   722→            free(tus->counters);
   723→        }
   724→        tus->counters = counters;
   725→        tus->num_stats = stats_num;
   726→
   727→        pthread_mutex_unlock(&thr->stats.mutex);
   728→    }
   729→    // also grab the concurrent request limit
   730→    thr->proxy_active_req_limit = ctx->active_req_limit;
   731→    STAT_UL(ctx);
   732→
   733→    // update limit counter(s)
   734→    pthread_mutex_lock(&thr->proxy_limit_lock);
   735→    thr->proxy_buffer_memory_limit = ctx->buffer_memory_limit;
   736→    pthread_mutex_unlock(&thr->proxy_limit_lock);
   737→
   738→    return 0;
   739→}
